CREATE TABLE `CommunityInstallOperation` (
  `id` VARCHAR(191) NOT NULL, `requestId` VARCHAR(191) NOT NULL, `idempotencyKey` VARCHAR(191) NOT NULL, `packageId` VARCHAR(191) NOT NULL, `releaseId` VARCHAR(191) NOT NULL, `accountId` VARCHAR(191) NOT NULL, `mode` VARCHAR(191) NOT NULL, `status` VARCHAR(191) NOT NULL DEFAULT 'PLANNED', `destinationRevision` VARCHAR(191) NOT NULL, `plan` LONGTEXT NOT NULL, `finalizationErrorCode` VARCHAR(191) NULL, `completedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL,
  PRIMARY KEY (`id`), UNIQUE INDEX `CommunityInstallOperation_idempotencyKey_key` (`idempotencyKey`), UNIQUE INDEX `CommunityInstallOperation_accountId_requestId_key` (`accountId`,`requestId`), INDEX `CommunityInstallOperation_packageId_status_idx` (`packageId`,`status`),
  CONSTRAINT `CommunityInstallOperation_packageId_fkey` FOREIGN KEY (`packageId`) REFERENCES `CommunityPackage`(`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `CommunityInstallOperation_releaseId_fkey` FOREIGN KEY (`releaseId`) REFERENCES `CommunityRelease`(`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `CommunityInstallOperation_accountId_fkey` FOREIGN KEY (`accountId`) REFERENCES `UserAccount`(`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `CommunityInstallMapping` (`id` VARCHAR(191) NOT NULL, `operationId` VARCHAR(191) NOT NULL, `sourceId` VARCHAR(191) NOT NULL, `targetId` VARCHAR(191) NOT NULL, `kind` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `CommunityInstallMapping_operationId_sourceId_key` (`operationId`,`sourceId`), CONSTRAINT `CommunityInstallMapping_operationId_fkey` FOREIGN KEY (`operationId`) REFERENCES `CommunityInstallOperation`(`id`) ON DELETE CASCADE ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
